          data,
          status: MarketplaceStatus.SUCCESS,
          error: undefined,
        },
      })),
    setError: error =>
      set(state => ({
        marketplace: {
          ...state.marketplace,
          error,
        },
      })),
    reset: () =>
      set({
        marketplace: initialMarketplaceState,
      }),
  },
});

