     7→function extractPointsQuantity(parameterization: ParametrizationData[]): number {
     8→  const pointsRescueItem = parameterization?.find(
     9→    item => item.category === 'pointsRescueSentence'
    10→  );
    11→
    12→  if (!pointsRescueItem?.value) {
    13→    return 0;
    14→  }
    15→
    16→  try {
    17→    let parsedValue = JSON.parse(pointsRescueItem.value);
    18→
    19→    if (typeof parsedValue === 'string') {
    20→      parsedValue = JSON.parse(parsedValue);
    21→    }
    22→
    23→    if (parsedValue && parsedValue.pointsQuantity !== undefined) {
    24→      const ptsQuantity = Number(parsedValue.pointsQuantity);
    25→
    26→      if (!isNaN(ptsQuantity) && ptsQuantity >= 0) {
