import type { PointsProduct, PointsProductsApiResponse } from '../models';

export function mapPointsProductsResponse(
  response: PointsProductsApiResponse,
): PointsProduct[] {
  const products = response?.data?.products;
  if (!products || !Array.isArray(products)) {
    return [];
  }
  return products;
}

export function extractConversionFactor(products: PointsProduct[]): number {
  for (let i = 0; i < products.length; i++) {
    const product = products[i];
    if (product.convertionFactor && product.convertionFactor > 0) {
      return product.convertionFactor;
    }
  }
  return 0;
}

export function findInvoiceProduct(
  products: PointsProduct[],
): PointsProduct | undefined {
  return products.find(
    product =>
      product.name?.toLowerCase().includes('fatura') ||
      product.action?.toLowerCase().includes('fatura'),
  );
}

