### Phase 1: Fix pointsQuantity Extraction (CRITICAL)

**File**: `src/services/services/parameter.service.ts`

Update service to handle original response structure and add function:
```typescript
function extractPointsQuantity(
  parameterization: ParameterPointsProgramResponse[]
): number {
  const pointsRescueItem = parameterization?.find(
    item => item.category === 'pointsRescueSentence'
  );
  if (!pointsRescueItem?.value || typeof pointsRescueItem.value !== 'string') {
    return 0;
  }
  try {
    let parsedValue = JSON.parse(pointsRescueItem.value);
    if (typeof parsedValue === 'string') {
      parsedValue = JSON.parse(parsedValue);
    }
    if (parsedValue?.pointsQuantity !== undefined) {
      const ptsQuantity = Number(parsedValue.pointsQuantity);
      if (!isNaN(ptsQuantity) && ptsQuantity >= 0) {
        return ptsQuantity;
      }
    }
    return 0;
  } catch (error) {
    console.error('Error parsing pointsQuantity:', error);
    return 0;
  }
}
```

